var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그 나이에 벌써 낙엽을 다섯 번 베는 경지라니. 정말 장하구나, 사나에.","JPN":"その歳でもう落ちゆく葉を五回斬るなんて。立派だね、早苗。","ENG":"Already able to slice falling leaves five times at that age... Impressive, Sanae.","TWN":"小小年紀竟然已經可以砍五次落葉，很厲害喔，早苗。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"너라면 분명 하야미 가문이 찾는 검술의 경지에 닿을 수 있을 거야.","JPN":"あなたならきっと、速水家の求める剣術の高みに辿り着けるわ。","ENG":"I am confident that you will reach the pinnacle of the swordsmanship for which the Hayami family has yearned.","TWN":"你一定能達到速水家族追求的劍法境界。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"가문 어르신들도 그러셨어요.","JPN":"家門のみんなもそうおっしゃっていました。","ENG":"The elders have also said that to me.","TWN":"家族的長輩們也曾說過，"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어머니께서 나나하라류의 경지를 깨닫지 못하니 제가 해야 한다고 합니다.","JPN":"母上が七原流の高みに辿り着けないから私がやらなければならないと。","ENG":"Mother was not able to reach it, so that it is my duty to do so.","TWN":"因為母親沒能領悟七原流的境界，所以必須由我來領悟。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어머니만큼 강한 분도 없는데…… 그런 말은 이상합니다.","JPN":"母上ほど強い方もいないのに……おかしなことをいうものです。","ENG":"There is no one as strong as you... So those words sound strange to me.","TWN":"可是明明就沒人像母親一樣強……那句話好奇怪。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"……사나에. 엄마가 나나하라류 검술의 다른 이름이 뭐라고 했는지 기억하니?","JPN":"……早苗。七原流剣術の別名を教えたけれど、なんだったか覚えてる？","ENG":"...Sanae. Do you remember what the other name for Nanahara Style is?","TWN":"……早苗，你還記得媽媽說過，七原流劍法的另一個名稱是什麼嗎？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"보이지 않는 것을 베는 검…… 입니다.","JPN":"見えないものを斬る剣……です。","ENG":"The blade that slashes the unseen...","TWN":"叫斬殺看不見之存在的劍……"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그래, 나나하라류의 본질은 영혼을 베는 명부신의 검술이며, 눈에 보이지 않는 것을 베는 힘이야.","JPN":"そう、七原流の本質は魂を斬る冥府の神の剣術であり、目に見えないものを斬る力なの。","ENG":"Yes. The essence of the Nanahara Style is the Nether God's swordsmanship that slashes the soul. It slices what cannot be seen.","TWN":"沒錯，七原流的本質是斬殺靈魂的冥府神劍法，是斬殺肉眼看不見之存在的力量。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"하지만 엄마는 어둠 속에만 서면 너무 많은 후회와 잡념들에 사로잡혀버려.","JPN":"でも母は闇の中に立つと後悔と雑念ばかりに囚われてしまう。","ENG":"But whenever I stand in the dark, regrets and stray thoughts consume me.","TWN":"但是媽媽只要站在黑暗中，就會被太多的悔恨和雜念給干擾。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그래서 눈앞이 캄캄해지면 쉽게 균형을 잃어버리고 말거든.","JPN":"それで、闇で目が見えなくなるとすぐバランスを崩すの。","ENG":"So, in the dark, I lose my balance easily.","TWN":"因此一旦眼前變黑，就很容易失去平衡。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"이 가면이 어둠을 밝혀 주긴 하지만, 도구에 의존하면 아무것도 깨달을 수 없으니까.","JPN":"この仮面が闇を照らしてはくれるけど、道具に頼ってはなにも悟ることはできないから。","ENG":"This mask fends away darkness, but one cannot reach the end while relying on such tools.","TWN":"這個面具雖然可以照亮黑暗，但太依賴工具的話反而就什麼都無法領悟到。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"하지만…… 강하고 굳센 내 딸이라면 할 수 있을 거야.","JPN":"でもね……心身ともに強い私の娘ならできるはずよ。","ENG":"But I believe... that you, strong and determined, will be able to.","TWN":"不過……我堅強的女兒一定能做到的。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"사나에, 너라면……","JPN":"早苗、あなたなら……","ENG":"Sanae, you...","TWN":"早苗，你的話……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"……어둠 앞에서도 평정을 잃지 않고, 사람들을 지킬 수 있을 거야.","JPN":"……闇の前でも平常心を失わずに、人々を守れる。","ENG":"...will be able to protect others in the face of darkness without disrupting your peace.","TWN":"……一定能在黑暗面前也不失去平靜，一定能保護別人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"커헉!","JPN":"がはっ！","ENG":"Kuh!","TWN":"咳咳！"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키!","JPN":"雅紀！","ENG":"Masaki!","TWN":"雅紀！"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};